import{_ as a,o as t,c as n,af as s}from"./chunks/framework.Bv7UzdO-.js";const g=JSON.parse('{"title":"Storage Engine","description":"","frontmatter":{},"headers":[],"relativePath":"en/posts/architecture/storage-engine.md","filePath":"en/posts/architecture/storage-engine.md","lastUpdated":1776948174000}'),i={name:"en/posts/architecture/storage-engine.md"};function o(l,e,r,d,c,p){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="storage-engine" tabindex="-1">Storage Engine <a class="header-anchor" href="#storage-engine" aria-label="Permalink to &quot;Storage Engine&quot;">вҖӢ</a></h1><p>The low-level engine is an append-only segmented log.</p><h2 id="write-path" tabindex="-1">Write Path <a class="header-anchor" href="#write-path" aria-label="Permalink to &quot;Write Path&quot;">вҖӢ</a></h2><ol><li>Construct Record: Magic(2B) + Op(1B) + KeyLen(4B) + ValLen(4B) + Key + Value + CRC32(4B)</li><li>Write to active segment file</li><li>Flush + Sync (fsync)</li><li>Update in-memory HashMap</li><li>Update Index (key вҶ’ segmentID + offset)</li><li>Update Bloom Filter</li><li>Rotate segment if &gt;= 16MB</li></ol><h2 id="read-path" tabindex="-1">Read Path <a class="header-anchor" href="#read-path" aria-label="Permalink to &quot;Read Path&quot;">вҖӢ</a></h2><ol><li>In-memory HashMap lookup вҶ’ O(1)</li><li>Bloom Filter check for missing keys</li><li>No disk I/O for reads</li></ol><h2 id="binary-record-format" tabindex="-1">Binary Record Format <a class="header-anchor" href="#binary-record-format" aria-label="Permalink to &quot;Binary Record Format&quot;">вҖӢ</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ</span></span>
<span class="line"><span>в”Ӯ Magic в”Ӯ  Op  в”Ӯ KeyLen в”Ӯ ValLen в”Ӯ Key в”Ӯ Value в”Ӯ CRC32 в”Ӯ</span></span>
<span class="line"><span>в”Ӯ 2B    в”Ӯ 1B   в”Ӯ 4B     в”Ӯ 4B     в”Ӯ ... в”Ӯ ...   в”Ӯ 4B    в”Ӯ</span></span>
<span class="line"><span>в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ</span></span></code></pre></div><p>Magic = <code>0xF0F1</code>, Op = <code>1</code> (Set) or <code>2</code> (Delete)</p><h2 id="segments" tabindex="-1">Segments <a class="header-anchor" href="#segments" aria-label="Permalink to &quot;Segments&quot;">вҖӢ</a></h2><ul><li>Files: <code>segment-{N}.dat</code></li><li>Max size: 16MB per segment</li><li>Compaction: rewrite all live keys to fresh <code>segment-0</code>, delete old segments</li></ul><h2 id="deletions" tabindex="-1">Deletions <a class="header-anchor" href="#deletions" aria-label="Permalink to &quot;Deletions&quot;">вҖӢ</a></h2><p>Write <code>Op=Delete</code> record, remove from in-memory HashMap and index. Old data cleaned up during compaction.</p><h2 id="snapshots" tabindex="-1">Snapshots <a class="header-anchor" href="#snapshots" aria-label="Permalink to &quot;Snapshots&quot;">вҖӢ</a></h2><p>Binary file <code>index.snapshot</code> for fast restart:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Magic(8B) + EntryCount(4B) + [KeyLen(4B) + Key + SegmentID(8B) + Offset(8B)]...</span></span></code></pre></div>`,16)])])}const m=a(i,[["render",o]]);export{g as __pageData,m as default};
